create extension if not exists pgcrypto;
create type public.level_kind as enum ('lesson','branch','boss');
create type public.order_status as enum ('pending','paid','failed','refunded');
create table public.profiles (id uuid primary key references auth.users on delete cascade, display_name text not null default '远征者', xp integer not null default 0 check(xp>=0), created_at timestamptz not null default now());
create table public.guest_accounts (id uuid primary key default gen_random_uuid(), anonymous_key_hash text not null unique, merged_user_id uuid references auth.users, created_at timestamptz not null default now());
create table public.user_goals (user_id uuid primary key references auth.users on delete cascade, goal text not null, daily_minutes integer not null check(daily_minutes between 5 and 120), updated_at timestamptz not null default now());
create table public.worlds (id text primary key, name text not null, slug text not null unique, description text not null, theme text not null, free_chapter_count integer not null default 1, published boolean not null default false, version integer not null default 1);
create table public.chapters (id text primary key, world_id text not null references public.worlds on delete cascade, name text not null, sort integer not null, is_free boolean not null default false, product_id text, published boolean not null default false, version integer not null default 1);
create table public.levels (id text primary key, chapter_id text not null references public.chapters on delete cascade, name text not null, kind public.level_kind not null, sort integer not null, pass_score integer not null default 60, reward_xp integer not null default 0, published boolean not null default false, version integer not null default 1);
create table public.knowledge_points (id text primary key, name text not null, summary text not null, core_fact text not null, category text not null, common_mistake text, memory_tip text, source text, source_date date, stable boolean not null default true, published boolean not null default false, version integer not null default 1);
create table public.knowledge_relations (id uuid primary key default gen_random_uuid(), source_id text not null references public.knowledge_points on delete cascade, target_id text not null references public.knowledge_points on delete cascade, relation_type text not null, label text not null, weight numeric not null default 1, unique(source_id,target_id,relation_type));
create table public.questions (id text primary key, knowledge_id text not null references public.knowledge_points, level_id text not null references public.levels, question_type text not null, stem text not null, options jsonb not null, correct_answer jsonb not null, explanation text not null, difficulty smallint not null check(difficulty between 1 and 5), published boolean not null default false, version integer not null default 1);
create table public.learning_sessions (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users, guest_id uuid references public.guest_accounts, level_id text references public.levels, status text not null default 'active', score integer not null default 0, started_at timestamptz not null default now(), completed_at timestamptz, check((user_id is not null) <> (guest_id is not null)));
create table public.question_attempts (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users, session_id uuid not null references public.learning_sessions on delete cascade, question_id text not null references public.questions, answer jsonb not null, is_correct boolean not null, time_spent_ms integer not null check(time_spent_ms>=0), used_hint boolean not null default false, mastery_delta integer not null, idempotency_key uuid not null unique, created_at timestamptz not null default now());
create table public.knowledge_mastery (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users on delete cascade, knowledge_id text not null references public.knowledge_points, mastery_score integer not null default 0 check(mastery_score between 0 and 100), correct_count integer not null default 0, wrong_count integer not null default 0, streak_correct integer not null default 0, last_result boolean, last_reviewed_at timestamptz, next_review_at timestamptz, status text not null default 'new', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(user_id,knowledge_id));
create table public.review_schedule (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users on delete cascade, knowledge_id text not null references public.knowledge_points, due_at timestamptz not null, interval_days numeric not null default 0, state text not null default 'due', unique(user_id,knowledge_id));
create table public.wrong_questions (user_id uuid not null references auth.users on delete cascade, question_id text not null references public.questions, wrong_count integer not null default 1, last_wrong_at timestamptz not null default now(), resolved_at timestamptz, primary key(user_id,question_id));
create table public.chapter_progress (user_id uuid not null references auth.users on delete cascade, chapter_id text not null references public.chapters, progress integer not null default 0 check(progress between 0 and 100), primary key(user_id,chapter_id));
create table public.level_progress (user_id uuid not null references auth.users on delete cascade, level_id text not null references public.levels, stars smallint not null default 0 check(stars between 0 and 3), best_score integer not null default 0, completed_at timestamptz, primary key(user_id,level_id));
create table public.products (id text primary key, name text not null, description text not null, price_cents integer not null check(price_cents>=0), entitlement_code text not null, active boolean not null default true);
create table public.orders (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users, product_id text not null references public.products, amount_cents integer not null, status public.order_status not null default 'pending', provider text not null, provider_order_id text unique, created_at timestamptz not null default now(), paid_at timestamptz);
create table public.payment_events (id uuid primary key default gen_random_uuid(), order_id uuid not null references public.orders, provider_event_id text not null unique, event_type text not null, verified boolean not null, received_at timestamptz not null default now());
create table public.entitlements (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users, entitlement_code text not null, source_order_id uuid references public.orders, starts_at timestamptz not null default now(), expires_at timestamptz, status text not null default 'active', unique(user_id,entitlement_code,source_order_id));
create index mastery_due_idx on public.knowledge_mastery(user_id,next_review_at); create index attempts_user_created_idx on public.question_attempts(user_id,created_at desc); create index levels_chapter_sort_idx on public.levels(chapter_id,sort);
alter table public.profiles enable row level security; alter table public.user_goals enable row level security; alter table public.learning_sessions enable row level security; alter table public.question_attempts enable row level security; alter table public.knowledge_mastery enable row level security; alter table public.review_schedule enable row level security; alter table public.wrong_questions enable row level security; alter table public.chapter_progress enable row level security; alter table public.level_progress enable row level security; alter table public.orders enable row level security; alter table public.entitlements enable row level security;
create policy "own profile" on public.profiles for all using(auth.uid()=id) with check(auth.uid()=id); create policy "own goals" on public.user_goals for all using(auth.uid()=user_id) with check(auth.uid()=user_id); create policy "own mastery" on public.knowledge_mastery for select using(auth.uid()=user_id); create policy "own reviews" on public.review_schedule for select using(auth.uid()=user_id); create policy "own wrongs" on public.wrong_questions for select using(auth.uid()=user_id); create policy "own orders" on public.orders for select using(auth.uid()=user_id); create policy "own entitlements" on public.entitlements for select using(auth.uid()=user_id);
-- No anonymous SELECT policy is granted on questions: gameplay reads sanitized views through the API only.
